#include <stdio.h>
#include <signal.h>
#include <unistd.h>

void handler(int signum) {
 printf("Caught signal %d\n", signum);
}

int main() {
 struct sigaction sa;
 sigset_t block_set, pending_set;

 // Setup signal handler
 sa.sa_handler = handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;
 sigaction(SIGUSR1, &sa, NULL);

 // Block SIGUSR1
 sigemptyset(&block_set);
 sigaddset(&block_set, SIGUSR1);
 sigprocmask(SIG_BLOCK, &block_set, NULL);

 // Generate SIGUSR1 (will be pending)
 raise(SIGUSR1);

 // Check pending signals
 sigpending(&pending_set);
 if (sigismember(&pending_set, SIGUSR1)) {
 printf("SIGUSR1 is pending!\n");
 }

 // Unblock SIGUSR1 - will be delivered
 sigprocmask(SIG_UNBLOCK, &block_set, NULL);

 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <unistd.h>

volatile sig_atomic_t got_signal = 0;

void handler(int signum) {
 got_signal = 1;
}

int main() {
 struct sigaction sa;
 sigset_t block_set, pending_set;

 // Setup handler
 sa.sa_handler = handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;
 sigaction(SIGUSR1, &sa, NULL);

 // Block SIGUSR1 and SIGUSR2
 sigemptyset(&block_set);
 sigaddset(&block_set, SIGUSR1);
 sigaddset(&block_set, SIGUSR2);
 sigprocmask(SIG_BLOCK, &block_set, NULL);

 printf("Waiting for signals...\n");

 // Poll pending signals until SIGUSR1 arrives
 while (1) {
 sigpending(&pending_set);
 if (sigismember(&pending_set, SIGUSR1)) {
 printf("SIGUSR1 detected as pending!\n");
 break;
 }
 // Do other work
 sleep(1);
 }

 // Unblock to handle
 sigprocmask(SIG_UNBLOCK, &block_set, NULL);

 return 0;
}

#include <stdio.h>
#include <signal.h>

int main() {
 sigset_t signal_set;

 // Initialize empty set
 sigemptyset(&signal_set);
 printf("After empty: %d\n", 
 sigismember(&signal_set, SIGTERM));

 // Add signals to set
 sigaddset(&signal_set, SIGTERM);
 sigaddset(&signal_set, SIGUSR1);
 printf("SIGTERM in set: %d\n", 
 sigismember(&signal_set, SIGTERM));
 printf("SIGKILL in set: %d\n", 
 sigismember(&signal_set, SIGKILL));

 // Remove signal from set
 sigdelset(&signal_set, SIGTERM);
 printf("After delete SIGTERM: %d\n", 
 sigismember(&signal_set, SIGTERM));

 // Demonstrate fillset
 sigfillset(&signal_set);
 printf("After fillset SIGTERM: %d\n", 
 sigismember(&signal_set, SIGTERM));

 return 0;
}
